#!/usr/bin/env python3
# Generated by scripts/generate_activities.py
# To update: edit quiz-data/pytest-dojo.json and re-run the generator.
"""Pytest Dojo

Learn pytest by writing real tests against a tiny phrasebook module: fix a broken assertion, then write a parametrized test, a pytest.raises(ValueError) test, a tmp_path fixture test, and a @pytest.mark.slow test that -m 'not slow' deselects. The launcher collects and runs your test suite itself to check your work.
"""
import os, shutil, subprocess, sys, tempfile, zipfile

# -- Crypto / obfuscation --
import hashlib as _hl, hmac as _hm

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000
_BLOB      = "f909088f172b56d12c6508481ca0f311dd25c7e14a1c6e51eda52b16d41a233c5773d1e83c57e761270c7e6ae9232381bd1b3206641a3079f49f7499c77194"

def _decrypt(key_str):
    key  = _hl.pbkdf2_hmac("sha256", key_str.encode(), _SALT, _KDF_ITERS)
    blob = bytes.fromhex(_BLOB)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    ks, i, stream = b"", 0, b""
    while len(stream) < len(ct):
        stream += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return bytes(a ^ b for a, b in zip(ct, stream)).decode()

# -- Helpers --
import textwrap as _tw

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _wrap(text):
    return _tw.wrap(text, width=_LINE_WIDTH - 4,
                    initial_indent="  ", subsequent_indent="    ")

def _show_wrong(raw, wrong_dict):
    exp = wrong_dict.get(raw)
    if exp:
        print()
        for ln in _wrap(f"[wrong] {exp}"):
            print(ln)
    else:
        print(f"  [wrong] {raw!r} is not the correct answer.")

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()

def die(msg):
    print(f"error: {msg}", file=sys.stderr)
    sys.exit(1)


SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, "repo.zip")

def _extract_repo():
    if not os.path.isfile(REPO_ZIP):
        die("repo.zip not found.")
    work_dir = tempfile.mkdtemp(prefix="pytest-dojo-")
    with zipfile.ZipFile(REPO_ZIP, "r") as zf:
        zf.extractall(work_dir)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        die("unexpected zip structure")
    return work_dir, os.path.join(work_dir, entries[0])

def _make_rcfile(repo_dir):
    banner_text = """
      ============================================================
       Pytest Dojo
      ============================================================

       phrasebook.py is a small, working module. The tests are the
       part that needs you. The checker looks tests up BY NAME, so
       use the exact names below.
       
       Step 1 -- run the suite and fix the broken test
         pytest -q
         One test fails. Read the report: the assertion, both values,
         and the arrow. Fix the expectation to match what shout()
         really returns.
       
       Step 2 -- write the four missing tests (see README for depth)
         test_translate_pairs           parametrize, 3 or more cases
         test_translate_rejects_unknown pytest.raises(ValueError)
         test_phrasebook_roundtrip      tmp_path: save, load, compare
         test_full_dictionary_scan      marked @pytest.mark.slow
       
       Step 3 -- watch pytest see your tests
         pytest --collect-only -q
         Every test you wrote should appear, the parametrized one
         once per case.
       
       Step 4 -- prove the marker works
         pytest -m 'not slow' -q
         The slow scan should show up as '1 deselected'.
       
       When everything passes, type 'exit'. The launcher collects and
       runs your suite itself -- it trusts pytest, not you -- and
       unlocks the passphrase.
      ============================================================

    """
    rcfile = tempfile.NamedTemporaryFile(mode="w", suffix=".rc", delete=False)
    rcfile.write(
        f'PS1=\'\\u@pytest-dojo:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "cat << 'BANNER'\n" + banner_text + "\nBANNER\n"
    )
    rcfile.close()
    return rcfile

def _drop_to_shell(repo_dir):
    rcfile = _make_rcfile(repo_dir)
    shell = os.environ.get("SHELL", "/bin/bash")
    try:
        subprocess.run([shell, "--rcfile", rcfile.name])
    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass

def run_shell_drop_once():
    work_dir, repo_dir = _extract_repo()
    _drop_to_shell(repo_dir)
    return repo_dir, work_dir

def run_shell_drop_with_retry(is_ready, not_ready_lines):
    work_dir, repo_dir = _extract_repo()
    while True:
        _drop_to_shell(repo_dir)
        if is_ready(repo_dir):
            return repo_dir, work_dir
        print()
        for line in not_ready_lines(repo_dir):
            print(line)
        print()
        try:
            again = input("  Try again? [y/n] ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            print()
            shutil.rmtree(work_dir, ignore_errors=True)
            return None, None
        if again != "y":
            shutil.rmtree(work_dir, ignore_errors=True)
            return None, None

def run_shell_drop_validated(check):
    work_dir, repo_dir = _extract_repo()
    try:
        while True:
            _drop_to_shell(repo_dir)
            print()
            _banner("Pytest Dojo -- Checking Your Work")
            print()
            passphrase, feedback = check(repo_dir)
            if passphrase is not None:
                _show_passphrase(passphrase)
                return True
            for line in feedback:
                print(line)
            print()
            try:
                again = input("  Try again? [y/n] ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print()
                return False
            if again != "y":
                return False
            print()
    finally:
        shutil.rmtree(work_dir, ignore_errors=True)

class ActivityEngine:
    """Core build/run/validate logic for Pytest Dojo; importable without a TTY."""

    slug = "pytest-dojo"
    title = "Pytest Dojo"
    description = "Learn pytest by writing real tests against a tiny phrasebook module: fix a broken assertion, then write a parametrized test, a pytest.raises(ValueError) test, a tmp_path fixture test, and a @pytest.mark.slow test that -m 'not slow' deselects. The launcher collects and runs your test suite itself to check your work."

    _REQUIRED = [
        "test_translate_rejects_unknown",
        "test_phrasebook_roundtrip",
        "test_full_dictionary_scan",
    ]

    def _run(self, args, repo_dir):
        try:
            r = subprocess.run(args, capture_output=True, text=True,
                               timeout=120, cwd=repo_dir)
        except subprocess.TimeoutExpired:
            return None, "timeout"
        return r.returncode, (r.stdout + "\n" + r.stderr)

    def _tests_source(self, repo_dir):
        src = ""
        tests_dir = os.path.join(repo_dir, "tests")
        if os.path.isdir(tests_dir):
            for fn in sorted(os.listdir(tests_dir)):
                if fn.endswith(".py"):
                    with open(os.path.join(tests_dir, fn), encoding="utf-8") as f:
                        src += f.read()
        return src

    def _check(self, repo_dir):
        if shutil.which("pytest") is None:
            return None, [
                "  pytest is not installed on this machine.",
                "  Install it the same way you installed your Python",
                "  toolchain in the env-setup-python activity:",
                "    uv tool install pytest",
            ]

        rc, out = self._run(["pytest", "--collect-only", "-q"], repo_dir)
        if rc is None:
            return None, ["  pytest --collect-only timed out."]
        if rc != 0:
            lines = ["  pytest could not collect your tests.  Its output:"]
            lines += [f"    {ln}" for ln in out.strip().splitlines()[:15]]
            return None, lines

        ids = [ln.strip() for ln in out.splitlines() if "::" in ln]
        problems = []
        n_param = sum(1 for i in ids if "::test_translate_pairs[" in i)
        if n_param < 3:
            problems.append(
                f"  test_translate_pairs: found {n_param} parametrized "
                "cases, need at least 3."
            )
        for name in self._REQUIRED:
            if not any(i.endswith("::" + name) or "::" + name + "[" in i for i in ids):
                problems.append(f"  missing required test: {name}")
        src = self._tests_source(repo_dir)
        if "pytest.raises(ValueError" not in src:
            problems.append(
                "  test_translate_rejects_unknown must use "
                "pytest.raises(ValueError)."
            )
        if "tmp_path" not in src:
            problems.append(
                "  test_phrasebook_roundtrip must use the tmp_path fixture."
            )
        if problems:
            return None, [
                "  Collection succeeded, but the required tests are not all",
                "  there yet (the checker looks them up by exact name):",
                "",
            ] + problems

        rc, out = self._run(["pytest", "-q"], repo_dir)
        if rc is None:
            return None, ["  pytest timed out."]
        if rc != 0:
            lines = [
                "  All required tests exist, but the suite does not pass.",
                "  Read the FIRST failure below:",
                "",
            ]
            lines += [f"    {ln}" for ln in out.strip().splitlines()[:20]]
            return None, lines

        rc, out = self._run(["pytest", "-m", "not slow", "-q"], repo_dir)
        if rc is None or rc != 0:
            return None, [
                "  pytest -m 'not slow' failed.",
            ] + [f"    {ln}" for ln in (out or "").strip().splitlines()[:10]]
        if "deselected" not in out:
            return None, [
                "  pytest -m 'not slow' deselected nothing.",
                "  test_full_dictionary_scan must carry the",
                "  @pytest.mark.slow marker so -m 'not slow' skips it.",
            ]
        rc, out = self._run(
            ["pytest", "-m", "not slow", "--collect-only", "-q"], repo_dir
        )
        if rc is None or "test_full_dictionary_scan" in out:
            return None, [
                "  -m 'not slow' still selects test_full_dictionary_scan.",
                "  The @pytest.mark.slow marker belongs on that test.",
            ]

        passphrase = _decrypt("collect=ok|all=pass|not-slow=deselects")
        if passphrase is not None:
            return passphrase, []
        return None, [
            "  Everything passed but the passphrase did not unlock.",
            "  Contact your instructor.",
        ]


    def check(self, repo_dir):
        """Build+run the student's repo; return (passphrase_or_None, feedback_lines)."""
        return self._check(repo_dir)


ENGINE = ActivityEngine()


def main():
    _banner(ENGINE.title)
    print()
    input("  Press Enter to begin...")

    ok = run_shell_drop_validated(ENGINE.check)
    if not ok:
        sys.exit(0)


if __name__ == "__main__":
    main()
